example.code:
# In cron: alert if backup script fails 0 3 * * * /home/nero/bin/backup.sh || notify-telegram.sh "Backup FAILED on $(hostname) at $(date '+%H:%M')"
# Wrapper function alert_on_failure() { local task_name="$1"; shift if ! "$@" 2>&1; then notify-telegram.sh "ALERT: *${task_name}* failed on $(hostname) at $(date '+%H:%M')" fi }
alert_on_failure "Daily Backup" /home/nero/bin/backup.sh
